 1	import * as React from 'react';
 2	import {
 3	  CommonModalProps,
 4	  ModalBody,
 5	  ModalHeader,
 6	} from '@odf/shared/modals/Modal';
 7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 8	import { Modal, ModalVariant } from '@patternfly/react-core';
 9	import CreateBackingStoreForm from './create-bs';
10	import '../mcg-endpoints/noobaa-provider-endpoints.scss';
11	
12	const CreateBackingStoreFormModal: React.FC<
13	  CreateBackingStoreFormModalProps
14	> = (props) => {
15	  const { t } = useCustomTranslation();
16	  const { isOpen, closeModal } = props;
17	
18	  const Header = <ModalHeader>{t('Create new BackingStore')}</ModalHeader>;
19	  return (
20	    <Modal
21	      isOpen={isOpen}
22	      variant={ModalVariant.small}
23	      header={Header}
24	      onClose={closeModal}
25	    >
26	      <div className="nb-endpoints__modal">
27	        <ModalBody>
28	          <p>
29	            {t(
30	              'BackingStore represents a storage target to be used as the underlying storage for the data in Multicloud Object Gateway buckets.'
31	            )}
32	          </p>
33	          <CreateBackingStoreForm onClose={closeModal} onCancel={closeModal} />
34	        </ModalBody>
35	      </div>
36	    </Modal>
37	  );
38	};
39	
40	type CreateBackingStoreFormModalProps = CommonModalProps & {
41	  namespace?: string;
42	};
43	
44	export default CreateBackingStoreFormModal;

