 8	  Title,
 9	  TitleSizes,
10	} from '@patternfly/react-core';
11	import './modal.scss';
12	
13	export type CommonModalProps<T = {}> = {
14	  isOpen: boolean;
15	  closeModal: () => void;
16	  extraProps: T;
17	};
18	
19	export const ModalBody: React.FC<ModalBoxBodyProps> = ({
20	  children,
21	  className,
22	  ...props
23	}) => (
24	  <ModalBoxBody
25	    className={classNames('modal--padding', 'modal--overflow', className)}
26	    {...props}
27	  >
28	    {children}
29	  </ModalBoxBody>
30	);
31	
32	type ModalHeaderProps = {
33	  className?: string;
34	};
35	
36	export const ModalHeader: React.FC<ModalHeaderProps> = ({
37	  children,
38	  className,
39	}) => (
40	  <Title headingLevel="h1" size={TitleSizes['2xl']} className={className}>
41	    {children}
42	  </Title>
43	);
44	
45	export const ModalFooter: React.FC<ModalBoxFooterProps> = ({
46	  children,
47	  className,
48	  ...props
49	}) => (
50	  <ModalBoxFooter
51	    className={classNames('modalFooter--justifyEnd', className)}
52	    {...props}
53	  >
54	    {children}
55	  </ModalBoxFooter>
56	);

